import { ROOT_ERROR_TYPE } from '../constants';
import type {
  FieldError,
  FieldErrors,
  FieldValues,
  InternalFieldName,
} from '../types';
import convertToArrayPayload from '../utils/convertToArrayPayload';
import get from '../utils/get';
import isPlainObject from '../utils/isPlainObject';
import set from '../utils/set';

export default <T extends FieldValues = FieldValues>(
  errors: FieldErrors<T>,
  error: Partial<Record<string, FieldError>>,
  name: InternalFieldName,
): FieldErrors<T> => {
  const existingError = get(errors, name);
  const hasNumericKeys = (value: unknown) =>
    typeof value === 'object' &&
    value !== null &&
    isPlainObject(value) &&
    Object.keys(value).some((key) => /^\d+$/.test(key));
  const fieldArrayErrors = hasNumericKeys(existingError)
    ? hasNumericKeys(error[name])
      ? error[name]
      : existingError
    : convertToArrayPayload(existingError);
  set(fieldArrayErrors, ROOT_ERROR_TYPE, error[name]);
  set(errors, name, fieldArrayErrors);
  return errors;
};
